#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,m,vis[N],ans;
vector<int> g[N];
void dfs(int x)
{
	vis[x]=1;
	for(int i=0;i<g[x].size();i++)
	{
		int v=g[x][i];
		if(vis[v]==0) dfs(v);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	for(int i=1;i<=n;i++)
	{
		if(vis[i]==0)
		{
			ans++;
			dfs(i);
		}
	}
	cout<<ans;
	return 0;
}
